script.text:
      /* <flatten type="Javascript"> */
function active$FormLot(f) {f.add_onResponseComplete(on$FormLot$ResponseComplete);}
function close$FormLot(f) {try {f.remove_onResponseComplete(on$FormLot$ResponseComplete)} catch (ex) {}}
function on$FormLot$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_lo');
      break;
    case 'LotInformation':
      var itemCode = $func.trim(f.getItem('ma_vt').value).toUpperCase();
      if (itemCode == f._itemCode) {
        f._lifeCycleDays = [result[0].Value;
        f._warrantyDays = [result[1].Value;
      }
      if (f._requestType == 0) changeExpireAndWarrantyDate(f, 0);
      break;
    default:
      break;
  }
}
function onChangeItem(o, type) {
  var f = o.parentForm;
  f._lifeCycleDays = null;
  f._warrantyDays = null;
  f._requestType = type;
  f._itemCode = $func.trim(o.value).toUpperCase();
  if (($func.trim(f._itemCode) != '') && (o.value.indexOf("'") == -1)) {
    f._lifeCycleText = f.getItem('ngay_hhsd').value;
    f._warrantyText = f.getItem('ngay_hhbh').value;
    f.request('LotInformation', 'LotInformation', ['ma_vt'], o);
  }
}

function onChangeReceiptDate(o) {window.setTimeout(String.format('setExpireAndWarrantyDate(\'{0}\');', o.parentForm.get_id()), 100);}
function setExpireAndWarrantyDate(id) {changeExpireAndWarrantyDate($find(id), 1);}
function changeExpireAndWarrantyDate(f, type) {
  var l = f.getItem('ngay_hhsd'), w = f.getItem('ngay_hhbh');
  if ((type == 0 && l.value == f._lifeCycleText) || type == 1) increaseDays(f, l, f._lifeCycleDays);
  if ((type == 0 && w.value == f._warrantyText) || type == 1) increaseDays(f, w, f._warrantyDays);
}

function increaseDays(f, o, d) {
  if (!d) return;
  var r = f.getItem('ngay_nhap');
  var v = $func.stringToValue(r.value, r.field, true);
  if (!v) return;
  v = new Date(v.getFullYear(), v.getMonth(), v.getDate() + parseInt(d));
  o._controlBehavior.set_selectedDate(v);
}
/* </flatten> */
      &ScriptIrregular;
